gameSettings.globalCss:
/* Transitions */

.transitions {
  transition: transform 1000ms
}

.transitions.dragging {
  transition: none
}

/* Make map options visible for all screen sizes and resolutions */

#buttonInputOverlay .modal {
  max-width: 95vw;
  overflow-x: auto;
}

#buttonInputOverlay .inputchoose > div {
  max-width: 100%;
  overflow: visible;
}

#buttonInputOverlay .inputchoose .inputchooseWidgetWrapper {
  overflow: visible;
}

#buttonInputOverlay .inputchoose .selected.inputchooseWidgetWrapper {
  overflow: visible;
}
